module regfile (
	input clk,
	input reset,
	input [1:0] write_addr,
	input [15:0] write_data,
	input write_en,
	input [1:0] read_addr,
	output reg [15:0] read_data
);reg [15:0] obf_registers [3:0];

always @(posedge clk) begin
	if (reset) begin
		obf_registers[0] <= 16'b0;
		obf_registers[1] <= 16'b0;
		obf_registers[2] <= 16'b0;
		obf_registers[3] <= 16'b0;
	end else if (write_en) begin
		obf_registers[write_addr] <= write_data;
	end
end

always @(*) begin
	read_data = obf_registers[read_addr];
end

endmodule
